                        alignItems: 'center',
                        justifyContent: 'center',
                      }}
                    >
                      {isLoading(page) && <Loader size="xs" />}
                    </div>
                  )}
                </div>
                <div
                  style={{
                    textAlign: 'center',
                    fontSize: 11,
                    color: 'var(--mantine-color-gray-7)',
                    height: LABEL_HEIGHT,
                    lineHeight: `${LABEL_HEIGHT}px`,
                  }}
                >
                  {page}
                </div>
              </div>
            )
          })}
        </div>
      </div>
      </div>

      {/* Resize drag handle */}
      <div
        onMouseDown={startDrag}
        style={{
          width: 4,
          height: '100%',
          cursor: 'col-resize',
          flexShrink: 0,
